class Solution {
public:
    ListNode* removeNthFromEnd(ListNode* head, int n) {
        ListNode* dummy = new ListNode(0, head);
        ListNode* first = head;
        ListNode* second = dummy;
        for (int i = 0; i < n; ++i) { // first 先走 n 步，保持与 second 间距为 n
            first = first->next;
        }
        while (first) {
            first = first->next;
            second = second->next;
        }
        second->next = second->next->next; // 此时 second 恰是待删节点的前驱
        ListNode* ans = dummy->next;
        delete dummy;
        return ans;
    }
};
